3549 Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
3550   Value *CondVal = SI.getCondition();
3551   Value *TrueVal = SI.getTrueValue();
3552   Value *FalseVal = SI.getFalseValue();
3553   Type *SelType = SI.getType();
3554 
3555   if (Value *V = simplifySelectInst(CondVal, TrueVal, FalseVal,
3556                                     SQ.getWithInstruction(&SI)))
3557     return replaceInstUsesWith(SI, V);
3558 
3559   if (Instruction *I = canonicalizeSelectToShuffle(SI))
3560     return I;
3561 
3562   if (Instruction *I = canonicalizeScalarSelectOfVecs(SI, *this))
3563     return I;
3564 
3565   // If the type of select is not an integer type or if the condition and
3566   // the selection type are not both scalar nor both vector types, there is no
3567   // point in attempting to match these patterns.
3568   Type *CondType = CondVal->getType();
3569   if (!isa<Constant>(CondVal) && SelType->isIntOrIntVectorTy() &&
3570       CondType->isVectorTy() == SelType->isVectorTy()) {
3571     if (Value *S = simplifyWithOpReplaced(TrueVal, CondVal,
3572                                           ConstantInt::getTrue(CondType), SQ,
3573                                           /* AllowRefinement */ true))
3574       return replaceOperand(SI, 1, S);
3575 
3576     if (Value *S = simplifyWithOpReplaced(FalseVal, CondVal,
3577                                           ConstantInt::getFalse(CondType), SQ,
3578                                           /* AllowRefinement */ true))
3579       return replaceOperand(SI, 2, S);
3580   }
3581 
3582   if (Instruction *R = foldSelectOfBools(SI))
3583     return R;
3584 
3585   // Selecting between two integer or vector splat integer constants?
3586   //
3587   // Note that we don't handle a scalar select of vectors:
3588   // select i1 %c, <2 x i8> <1, 1>, <2 x i8> <0, 0>
3589   // because that may need 3 instructions to splat the condition value:
3590   // extend, insertelement, shufflevector.
3591   //
3592   // Do not handle i1 TrueVal and FalseVal otherwise would result in
3593   // zext/sext i1 to i1.
3594   if (SelType->isIntOrIntVectorTy() && !SelType->isIntOrIntVectorTy(1) &&
3595       CondVal->getType()->isVectorTy() == SelType->isVectorTy()) {
3596     // select C, 1, 0 -> zext C to int
3597     if (match(TrueVal, m_One()) && match(FalseVal, m_Zero()))
3598       return new ZExtInst(CondVal, SelType);
3599 
3600     // select C, -1, 0 -> sext C to int
3601     if (match(TrueVal, m_AllOnes()) && match(FalseVal, m_Zero()))
3602       return new SExtInst(CondVal, SelType);
3603 
3604     // select C, 0, 1 -> zext !C to int
3605     if (match(TrueVal, m_Zero()) && match(FalseVal, m_One())) {
3606       Value *NotCond = Builder.CreateNot(CondVal, "not." + CondVal->getName());
3607       return new ZExtInst(NotCond, SelType);
3608     }
3609 
3610     // select C, 0, -1 -> sext !C to int
3611     if (match(TrueVal, m_Zero()) && match(FalseVal, m_AllOnes())) {
3612       Value *NotCond = Builder.CreateNot(CondVal, "not." + CondVal->getName());
3613       return new SExtInst(NotCond, SelType);
3614     }
3615   }
3616 
3617   auto *SIFPOp = dyn_cast<FPMathOperator>(&SI);
3618 
3619   if (auto *FCmp = dyn_cast<FCmpInst>(CondVal)) {
3620     FCmpInst::Predicate Pred = FCmp->getPredicate();
3621     Value *Cmp0 = FCmp->getOperand(0), *Cmp1 = FCmp->getOperand(1);
3622     // Are we selecting a value based on a comparison of the two values?
3623     if ((Cmp0 == TrueVal && Cmp1 == FalseVal) ||
3624         (Cmp0 == FalseVal && Cmp1 == TrueVal)) {
3625       // Canonicalize to use ordered comparisons by swapping the select
3626       // operands.
3627       //
